<template>
    <div id="header" class="d-flex justify-content-between"
        style="border-bottom: solid 1px #ccc; box-shadow: 0 6px 4px -1px rgb(216, 216, 216);">
        <div class="img-header">
            <router-link to="/home">
                <img alt="AngerPulse logo mini" class="p-2 imgHome" style="height: 60px; cursor: pointer;"
                    v-if="showImage" @click="$router.push({ name: 'Home' })" src="../assets/btnAngerPulseHeader.png">
            </router-link>
        </div>
        <div class="menu-header d-flex">
            <div class="m-auto">
                <label class="p-2" style="cursor: pointer;" @click="$i18n.locale = 'en'">
                    <img src="../assets/Flag_UK.svg" alt="English"
                        style="width: 20px; vertical-align: middle; margin-right: 5px;">
                    {{ t('info.En') }} /
                </label>
            </div>
            <div class="m-auto ps-2 pe-2">
                <label class="p-2" style="cursor: pointer;" @click="$i18n.locale = 'es'">
                    <img src="../assets/Flag_of_Spain.svg" alt="Español"
                        style="width: 20px; vertical-align: middle; margin-right: 5px;">
                    {{ t('info.Es') }}
                </label>
            </div>
            <div v-if="isLoggedIn" class="p-2" style="cursor: pointer;" data-bs-toggle="modal"
                data-bs-target="#modalMenu">
                <img alt="Menu" style="width: 40px; height: 100%" src="../assets/menu.svg">
            </div>
        </div>
    </div>

    <!-- Modal -->
    <div v-if="LanguageSpanish" class="modal fade right-slide" data-bs-scroll="true" id="modalMenu" tabindex="-1"
        aria-labelledby="exampleModalLabel" aria-hidden="true">
        <div class="modal-dialog modal-dialog-scrollable">
            <div class="modal-content" :style="!showMore ? 'overflow: visible;' : ''">
                <div class="modal-body" :style="!showMore ? 'overflow-y: visible;' : ''">
                    <div class="dv-menu" data-bs-dismiss="modal">
                        <router-link to="/dashboard" class="comfortaa-menu" v-html="t('menu.actividad')"></router-link>
                    </div>
                    <div class="dv-menu" data-bs-dismiss="modal">
                        <router-link to="/audioteca" class="comfortaa-menu" v-html="t('menu.audioteca')"></router-link>
                    </div>
                    <div class="dv-menu" data-bs-dismiss="modal">
                        <router-link to="/configuracion" class="comfortaa-menu" v-html="t('menu.audios')"></router-link>
                    </div>
                    <div class="dv-menu" data-bs-dismiss="modal">
                        <router-link to="/perfil" class="comfortaa-menu" v-html="t('menu.perfil')"></router-link>
                    </div>
                    <div class="dv-menu" data-bs-dismiss="modal">
                        <router-link to="/plan" class="comfortaa-menu" v-html="t('menu.pagos')"></router-link>
                    </div>
                    <div class="dv-menu" data-bs-dismiss="modal">
                        <a class="comfortaa-menu px-3" style="cursor: pointer;" v-html="t('menu.logout')"
                            @click="logout()"></a>
                    </div>
                    <!-- OPCIÓN GUÍA (SIEMPRE VISIBLE) -->
                    <div class="text-center mt-3 px-3" @click="toggleMore"
                        style="margin:15px; margin-bottom: 5px; cursor: pointer;">
                        <a class="comfortaa-menu" v-html="t('menu.guia')"></a>
                    </div>

                    <!-- BOTÓN DE DESPLIEGUE (ENTRE GUÍA Y SUB-OPCIONES) -->
                    <div class="d-flex justify-content-center"
                        style="position: relative; z-index: 10; margin-top: -5px; margin-bottom: -20px;">
                        <button class="btn shadow-sm" @click="toggleMore"
                            style="background-color: #fff; border-radius: 50%; width: 40px; height: 40px; display: flex; align-items: center; justify-content: center; padding: 0;">
                            <img alt="AngerPulse logo mini"
                                :style="{ transform: showMore ? 'rotate(180deg)' : 'none', transition: 'transform 0.3s ease', width: '24px', height: '24px' }"
                                src="../assets/arrow-down.svg">
                        </button>
                    </div>

                    <!-- SUB-OPCIONES -->
                    <div v-if="showMore" class="extra-options guia pb-4">
                        <div class="dv-menu" data-bs-dismiss="modal">
                            <router-link :to="{ path: '/info' }" class="comfortaa-menu"
                                v-html="t('menu.ira')"></router-link>
                        </div>
                        <div class="dv-menu" data-bs-dismiss="modal">
                            <router-link :to="{ path: '/info', hash: '#Angerpulse' }" class="comfortaa-menu"
                                v-html="t('menu.angerpulse')"></router-link>
                        </div>
                        <div class="dv-menu" data-bs-dismiss="modal">
                            <router-link :to="{ path: '/info', hash: '#Quien' }" class="comfortaa-menu"
                                v-html="t('menu.para')"></router-link>
                        </div>
                        <div class="dv-menu" data-bs-dismiss="modal">
                            <router-link :to="{ path: '/info', hash: '#Como' }" class="comfortaa-menu"
                                v-html="t('menu.como')"></router-link>
                        </div>
                        <div class="dv-menu" data-bs-dismiss="modal">
                            <router-link :to="{ path: '/info', hash: '#Cuando' }" class="comfortaa-menu"
                                v-html="t('menu.cuando')"></router-link>
                        </div>
                        <div class="dv-menu" data-bs-dismiss="modal">
                            <router-link :to="{ path: '/info', hash: '#Dashboard' }" class="comfortaa-menu"
                                v-html="t('menu.actividad_guia')"></router-link>
                        </div>
                        <div class="dv-menu" data-bs-dismiss="modal">
                            <router-link :to="{ path: '/info', hash: '#Audioteca' }" class="comfortaa-menu"
                                v-html="t('menu.audioteca_guia')"></router-link>
                        </div>
                        <div class="dv-menu" data-bs-dismiss="modal">
                            <router-link :to="{ path: '/info', hash: '#Config' }" class="comfortaa-menu"
                                v-html="t('menu.audios_guia')"></router-link>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <div class="content">
        <router-view></router-view>
    </div>
</template>

<script setup>
import { ref, watch, onMounted } from 'vue';
import { useRoute, useRouter } from 'vue-router'
import { useI18n } from 'vue-i18n'

const router = useRouter()
const { t } = useI18n()
const route = useRoute()

const isLoggedIn = ref(false);
const showImage = ref(true)
const LanguageSpanish = ref(true)
const showMore = ref(false);

const toggleMore = () => {
    showMore.value = !showMore.value
}

onMounted(() => {
    const token = localStorage.getItem('token')
    isLoggedIn.value = token !== null && token !== '' && token !== 'undefined'
});

watch(
    () => route.path,
    (newPath) => {
        showImage.value = newPath !== '/home' && newPath !== '/',
            isLoggedIn.value = localStorage.getItem('token') !== null && localStorage.getItem('token') !== '' && localStorage.getItem('token') !== 'undefined'
    },
    { immediate: true }
)

const logout = () => {
    localStorage.removeItem('token')
    isLoggedIn.value = false;
    router.push('/login')
}

document.addEventListener("hidden.bs.modal", function (event) {
    if (event.target.id === "modalMenu") {
        showMore.value = false;
    }
});
</script>

<style scoped>
a {
    text-decoration: none;
    width: 100%;
    display: flex;
    justify-content: center;
}

.btn-circle {
    width: 25px;
    height: 45px;
    border-radius: 50%;
    border: none;
    background: #e0e0e0;
    font-size: 24px;
    display: flex;
    justify-content: center;
    align-items: center;
    cursor: pointer;
}

.btn-circle:hover {
    background: #d0d0d0;
}

.extra-options {
    animation: fadeIn 0.3s ease;
}

@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(-5px);
    }

    to {
        opacity: 1;
        transform: translateY(0);
    }
}
</style>